static inline int landmask_get(int x, int y) {
    if ((unsigned)x >= (unsigned)LANDMASK_W) return 0;
    if ((unsigned)y >= (unsigned)LANDMASK_H) return 0;
    int bit = y * LANDMASK_W + x;
    return (k_landmask[bit >> 3] >> (7 - (bit & 7))) & 1;
}

